class Solution:
    def numberOfWays(self, n: int, x: int, y: int) -> int:
        MOD = 10**9 + 7
        result = 0
        for i in range(1, min(n, x) + 1):
            ways_to_assign = self.assign_stages(n, i)
            ways_to_score = pow(y, i, MOD)
            result = (result + ways_to_assign * ways_to_score) % MOD
        return result

    def assign_stages(self, n, k):
        MOD = 10**9 + 7
        result = self.stirling(n, k) * pow(k, n, MOD) % MOD
        return result

    def stirling(self, n, k):
        MOD = 10**9 + 7
        if n < k or k < 1:
            return 0
        if n == k or k == 1:
            return 1
        dp = [[0] * (k + 1) for _ in range(n + 1)]
        for i in range(1, n + 1):
            dp[i][1] = 1
        for i in range(1, n + 1):
            dp[i][i] = 1
        for i in range(2, n + 1):
            for j in range(2, min(i, k) + 1):
                dp[i][j] = (j * dp[i - 1][j] + dp[i - 1][j - 1]) % MOD
        return dp[n][k]
